import { getHeaderAndFooter } from "../../../src/lib/global-navigation/header-and-footer";
import { globalBaseConfig } from "../../../src/config/global-base-config";
import { setIGNHeaderAndFooter } from "../../../src/lib/global-navigation/ign";
import { getBrandCode } from "../../../src/lib/global-navigation/helpers";
import { getBetaFromHostname, isLocalhost } from "../../../src/lib/environment";

jest.mock("../../../src/lib/global-navigation/ign");
jest.mock("../../../src/lib/global-navigation/helpers");
jest.mock("../../../src/lib/environment");

beforeAll(() => {
  getBrandCode.mockImplementation((ao, def) => {
    if (ao.mockTo) {
      return ao.mockTo;
    }
    return def;
  });
  getBetaFromHostname.mockImplementation(() => {
    return false;
  });
  isLocalhost.mockImplementation(() => {
    return true;
  });
});

afterEach(() => {
  setIGNHeaderAndFooter.mockClear();
});

function ignResult(brand) {
  return {
    headerId: globalBaseConfig.AO.IGN.HEADER_ID,
    brandCode: brand,
    assetsLocationMap: globalBaseConfig.AO.IGN.assetsLocationMap,
    settings: {
      disableOpacityChange: undefined,
      version: undefined
    }
  };
}

test("Tests default configuration", () => {
  getHeaderAndFooter();

  expect(setIGNHeaderAndFooter.mock.calls.length).toBe(1);
  expect(setIGNHeaderAndFooter.mock.calls[0][0]).toMatchObject(ignResult("maeu"));
});

test("It loads the IGN for Sealand", () => {
  const config = {
    AO: globalBaseConfig.AO
  };
  config.AO.mockTo = "seau";
  getHeaderAndFooter(config);
  expect(setIGNHeaderAndFooter.mock.calls.length).toBe(1);
  expect(setIGNHeaderAndFooter.mock.calls[0][0]).toMatchObject(ignResult("seau"));
});

test("IGN is loaded if it is in beta", () => {
  getBetaFromHostname.mockImplementation(() => {
    return true;
  });
  const config = {
    AO: globalBaseConfig.AO
  };
  config.AO.mockTo = "seau";
  getHeaderAndFooter(config);
  expect(setIGNHeaderAndFooter.mock.calls.length).toBe(1);
});

test("IGN is loaded if it is in beta and the IGN is being forced", () => {
  getBetaFromHostname.mockImplementation(() => {
    return true;
  });
  const config = {
    AO: globalBaseConfig.AO,
    forceIGN: true
  };
  config.AO.mockTo = "seau";
  getHeaderAndFooter(config);
  expect(setIGNHeaderAndFooter.mock.calls.length).toBe(1);
});

test("It loads the default IGN, when brandParam is null", () => {
  const config = {
    AO: globalBaseConfig.AO,
    forceIGN: true,
    brandParam: null
  };
  config.AO.mockTo = "maeu";

  getHeaderAndFooter(config);
  expect(setIGNHeaderAndFooter.mock.calls[0][0]).toMatchObject(ignResult("maeu"));
});

test("It loads the default IGN, when brandParam is empty", () => {
  const config = {
    AO: globalBaseConfig.AO,
    forceIGN: true,
    brandParam: ""
  };
  config.AO.mockTo = "maeu";

  getHeaderAndFooter(config);
  expect(setIGNHeaderAndFooter.mock.calls[0][0]).toMatchObject(ignResult("maeu"));
});

test("It loads the IGN for Sealand, when brandParam value is seau and domain is localhost ", () => {
  const config = {
    AO: globalBaseConfig.AO,
    forceIGN: true,
    brandParam: "seau"
  };
  config.AO.mockTo = "maeu";

  getHeaderAndFooter(config);
  if (window.location.hostname.includes("localhost")) {
    expect(setIGNHeaderAndFooter.mock.calls[0][0]).toMatchObject(ignResult("seau"));
  } else {
    expect(setIGNHeaderAndFooter.mock.calls[0][0]).toMatchObject(ignResult("maeu"));
  }
});

test("It loads the IGN for Sealand, when brandParam value is seau and domain is localhost ", () => {
  const config = {
    AO: globalBaseConfig.AO,
    forceIGN: true,
    brandParam: "seau"
  };
  config.AO.mockTo = "maeu";

  getHeaderAndFooter(config);
  if (window.location.hostname.includes("localhost")) {
    expect(setIGNHeaderAndFooter.mock.calls[0][0]).toMatchObject(ignResult("seau"));
  } else {
    expect(setIGNHeaderAndFooter.mock.calls[0][0]).toMatchObject(ignResult("maeu"));
  }
});

test("It loads the sealand IGN when coming from the plugin with a brand", () => {
  const config = {
    AO: globalBaseConfig.AO,
    forceIGN: true,
    fromMaerskPlugin: true,
    brand: globalBaseConfig.BRANDS.find((b) => b.scacCode === "seau")
  };
  config.AO.mockTo = "seau";

  getHeaderAndFooter(config);
  expect(setIGNHeaderAndFooter.mock.calls[0][0]).toMatchObject(ignResult("seau"));
});
